function toggleMenu(){const e=document.getElementById("navLinks");e.classList.toggle("active"),document.body.classList.toggle("menu-open")}function closeMenu(){const e=document.getElementById("navLinks");e.classList.remove("active"),document.body.classList.remove("menu-open")}document.addEventListener("click",function(e){const t=document.getElementById("navLinks"),n=document.querySelector(".menu-btn");!t.contains(e.target)&&!n.contains(e.target)&&(t.classList.remove("active"),document.body.classList.remove("menu-open"))});function toggleDarkMode(){document.body.classList.toggle("dark");const e=document.querySelector(".toggle-btn");document.body.classList.contains("dark")?(localStorage.setItem("theme","dark"),e.textContent="☀"):(localStorage.setItem("theme","light"),e.textContent="🌙")}localStorage.getItem("theme")==="dark"&&(document.body.classList.add("dark"),document.querySelector(".toggle-btn").textContent="☀");function goToSearchPage(){window.location.href="/search/"}